from collections import Counter

def solve(s: str) -> str:
    vowels = {'a', 'e', 'i', 'o', 'u'}
    vowels_list = []
    vowel_counts = Counter()
    first_occurrence = {}

    # Collect vowels and their counts, and track first occurrence
    for idx, char in enumerate(s):
        if char in vowels:
            vowels_list.append(char)
            vowel_counts[char] += 1
            if char not in first_occurrence:
                first_occurrence[char] = idx

    # Sort vowels by frequency (descending) and then by first occurrence (ascending)
    sorted_vowels = sorted(vowels_list, key=lambda x: (-vowel_counts[x], first_occurrence[x]))

    # Reconstruct the string with sorted vowels
    result = []
    vowel_index = 0
    for char in s:
        if char in vowels:
            result.append(sorted_vowels[vowel_index])
            vowel_index += 1
        else:
            result.append(char)

    return ''.join(result)
